static class Solution {
        public long kthElement(int[] a, int[] b, int k) {
            int m = a.length;
            int n = b.length;
            if (m > n) return kthElement(b, a, k);

            int low = Math.max(0, k - n);
            int high = Math.min(k, m);

            while (low <= high) {
                int cut1 = low + (high - low) / 2;
                int cut2 = k - cut1;

                long l1 = (cut1 == 0) ? Long.MIN_VALUE : a[cut1 - 1];
                long l2 = (cut2 == 0) ? Long.MIN_VALUE : b[cut2 - 1];
                long r1 = (cut1 == m) ? Long.MAX_VALUE : a[cut1];
                long r2 = (cut2 == n) ? Long.MAX_VALUE : b[cut2];

                if (l1 <= r2 && l2 <= r1) return Math.max(l1, l2);
                else if (l1 > r2) high = cut1 - 1;
                else low = cut1 + 1;
            }
            return -1;
        }
    }

