/**
 * @param {number[]} a - First sorted array (parsed as Numbers)
 * @param {BigInt[]} b - Second sorted array (parsed as BigInts)
 * @param {number} k - The 1-based position to find
 * @return {number} - The K-th element
 */
function findKthElement(a, b, k) {
    // Helper function to safely find the true length of the sorted data.
    // This ignores any trailing `NaN` or `0n` artifacts created by trailing spaces.
    function getValidLength(arr) {
        let len = 0;
        for (let i = 0; i < arr.length; i++) {
            let val = Number(arr[i]);
            // Break if we hit a NaN or a sudden drop in value (meaning we hit a trailing 0n artifact)
            if (Number.isNaN(val)) break;
            if (i > 0 && val < Number(arr[i - 1])) break;
            len++;
        }
        return len;
    }

    // Get the exact, true lengths of the sorted numbers
    let m = getValidLength(a);
    let n = getValidLength(b);

    // Ensure we are binary searching on the smaller of the two arrays
    if (m > n) {
        return search(b, a, n, m, k);
    }
    return search(a, b, m, n, k);

    // Core Binary Search Logic
    function search(arr1, arr2, len1, len2, target) {
        let low = Math.max(0, target - len2);
        let high = Math.min(target, len1);

        while (low <= high) {
            let cut1 = Math.floor((low + high) / 2);
            let cut2 = target - cut1;

            // Normalize everything to standard Numbers safely
            let l1 = cut1 === 0 ? -Infinity : Number(arr1[cut1 - 1]);
            let l2 = cut2 === 0 ? -Infinity : Number(arr2[cut2 - 1]);

            let r1 = cut1 === len1 ? Infinity : Number(arr1[cut1]);
            let r2 = cut2 === len2 ? Infinity : Number(arr2[cut2]);

            // If valid partition is found
            if (l1 <= r2 && l2 <= r1) {
                return Math.max(l1, l2);
            } 
            // Took too many elements from arr1, move left
            else if (l1 > r2) {
                high = cut1 - 1;
            } 
            // Need more elements from arr1, move right
            else {
                low = cut1 + 1;
            }
        }
        return -1;
    }
}
